// Build the morning digest
const modelsData = $('Ollama Models').first().json;
const psData = $('Ollama Running').first().json;
const n8nData = $('n8n Health').first().json;
const kevinData = $('Kevin Quote').first().json;

// Models inventory
const allModels = (modelsData.models || []).map(m => m.name);
const personalities = ['kevin:latest', 'jason:latest', 'scaachi:latest', 'christian:latest', 'chidi:latest'];
const missingPersonalities = personalities.filter(p => !allModels.includes(p));

// Running models in VRAM
const runningModels = (psData.models || []).map(m => m.name);

// System status
const n8nOk = n8nData.status === 'ok';
const ollamaOk = allModels.length > 0;
const personalitiesOk = missingPersonalities.length === 0;

const overallStatus = (n8nOk && ollamaOk && personalitiesOk)
  ? '🟢 All systems operational'
  : '🟡 Degraded — check details below';

// Kevin's quote
const kevinQuote = kevinData.message?.content?.trim() || 'Ready to build great things today!';

// Day of week
const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const today = days[new Date().getDay()];
const dateStr = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

const digest = [
  `*🌅 Good Morning — ${today}, ${dateStr}*`,
  ``,
  `*Status:* ${overallStatus}`,
  ``,
  `*📊 System Health*`,
  `• n8n Automation: ${n8nOk ? '✅ Online' : '❌ Down'}`,
  `• Ollama Service: ${ollamaOk ? `✅ ${allModels.length} models` : '❌ Unreachable'}`,
  `• Personalities: ${personalitiesOk ? '✅ All 5 ready' : `⚠️ Missing: ${missingPersonalities.join(', ')}`}`,
  `• VRAM Loaded: ${runningModels.length > 0 ? runningModels.join(', ') : 'None (cold start)'}`,
  ``,
  `*🤖 Active Agents*`,
  `• Kevin O'Malley (Legal) — counsel-kevin, tasks-kevin`,
  `• Jason Mendoza (Engineering) — counsel-jason, tasks-jason`,
  `• Scaachi Koul (Marketing) — counsel-scaachi, tasks-scaachi`,
  `• Christian Lacy (Strategy) — counsel-christian, tasks-christian`,
  `• Chidi Anagonye (Research) — counsel-chidi, tasks-chidi`,
  ``,
  `*💬 Kevin's Morning Take*`,
  `_"${kevinQuote}"_`,
  ``,
  `_Use /ai-status for live status • /ai-diagnose for full diagnostics_`
].join('\n');

return [{ json: { digest } }];
